import os
import sqlite3
import base64
import re
import shutil
import urllib.parse
import secrets
from flask import Flask, request, jsonify, render_template, g, make_response

app = Flask(__name__)
app.config['DATABASE'] = '/tmp/aetheris.db'
app.config['SECRET_KEY'] = 'aetheris_propulsion_2024_ops_key'
# In-memory store for session tokens to prevent simple replay
valid_tokens = {}

def get_db():
    if 'db' not in g:
        if not os.path.exists(app.config['DATABASE']):
            shutil.copy('/app/aetheris.db', app.config['DATABASE'])
        g.db = sqlite3.connect(app.config['DATABASE'])
        g.db.row_factory = sqlite3.Row
    return g.db

@app.teardown_appcontext
def close_db(e):
    db = g.pop('db', None)
    if db is not None:
        db.close()

# --- Aegis-v5 Hardened Security Middleware ---
def aegis_v5_filter(payload):
    if not payload:
        return ""

    # 1. Normalize input (URL Decode)
    payload = urllib.parse.unquote(payload)

    # 2. Expand Whitespace/Comment Blacklist (Blocks Tabs, Newlines, etc.)
    # Calibrator: "whitespace filter is bypassed using standard character alternatives like tabs or newlines"
    # Fix: Added all common whitespace control characters and multiple comment styles.
    forbidden_chars = [' ', '\t', '\n', '\r', '\f', '\v', '--', '/*', '*/', '#', '`']
    if any(x in payload for x in forbidden_chars):
        return "BLOCK_ACTION"

    # 3. Recursive Keyword Scrubbing
    # Calibrator: "keyword filter is explicitly noted as non-recursive... trivially bypassable by doubling keywords"
    # Fix: Implemented a loop to recursively strip keywords until none remain.
    keywords = ['SELECT', 'UNION', 'WHERE', 'FROM', 'LIMIT', 'OFFSET', 'JOIN', 'AND', 'OR', 'LIKE', 'IN']
    sanitized = payload
    while True:
        changed = False
        for kw in keywords:
            pattern = re.compile(re.escape(kw), re.IGNORECASE)
            if pattern.search(sanitized):
                sanitized = pattern.sub('', sanitized)
                changed = True
        if not changed:
            break
    return sanitized

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/dashboard')
def dashboard():
    return render_template('dashboard.html', station_id="SITE-ALPHA-01")

@app.route('/api/v1/status')
def status():
    # Generate a one-time session token required for telemetry signature
    token = secrets.token_hex(16)
    valid_tokens[token] = True
    resp = jsonify({"status": "online", "systems": "nominal", "station": "SITE-ALPHA-01"})
    resp.headers['X-Session-Token'] = token
    return resp

@app.route('/api/v1/telemetry/stats', methods=['POST'])
def telemetry_stats():
    # Security Check 1: Multi-Step Header Verification
    token = request.headers.get('X-Session-Token')
    sig = request.headers.get('X-Station-Signature')
    ua = request.headers.get('User-Agent', '')

    if not token or token not in valid_tokens:
        return jsonify({"error": "Unauthorized: Missing or Invalid Session Token"}), 403

    # Expected sig is now dynamic: base64(token:station:ua)
    expected_sig = base64.b64encode(f"{token}:SITE-ALPHA-01:{ua}".encode()).decode()

    if sig != expected_sig:
        return jsonify({"error": "Unauthorized: Invalid Station Signature"}), 403

    data = request.get_json()
    group_by = data.get('group_by', 'mission_id')

    # Apply Aegis-v5 Filtering
    sanitized_group = aegis_v5_filter(group_by)
    if sanitized_group == "BLOCK_ACTION":
         return jsonify({"error": "Security Alert: Illegal characters detected by Aegis-v5"}), 400

    try:
        db = get_db()
        # Blind SQLi: Query success/fail is the only indicator
        # We remove the count from the response to force order-based or boolean extraction
        query = f"SELECT count(*), {sanitized_group} FROM telemetry_logs GROUP BY {sanitized_group}"
        results = db.execute(query).fetchall()

        return jsonify({
            "status": "success",
            "summary": {
                "segments": len(results)
            }
        })
    except Exception:
        # Blind SQLi: Error messages are stripped. No feedback for the attacker.
        return jsonify({"error": "Internal analytical engine fault"}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

