{% extends 'base.html' %}
{% block content %}
<h1>Command Dashboard</h1>
<div class="card">
    <h2>Local Node Info</h2>
    <p>Station Identifier: <strong>{{ station_id }}</strong></p>
    <p>Security Level: <strong>Aegis-v5 ENFORCED</strong></p>
</div>
<div class="card">
    <h2>Diagnostic Analytics</h2>
    <div id="stats-display">Initialising analytical engine...</div>
</div>
<script>
    const station_id = "{{ station_id }}";
    async function loadStats() {
        try {
            // Step 1: Get session token
            const statusRes = await fetch('/api/v1/status');
            const token = statusRes.headers.get('X-Session-Token');

            // Step 2: Compute hardened signature
            const sig = btoa(token + ":" + station_id + ":" + navigator.userAgent);

            // Step 3: Fetch telemetry
            const res = await fetch('/api/v1/telemetry/stats', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-Session-Token': token,
                    'X-Station-Signature': sig
                },
                body: JSON.stringify({ "group_by": "mission_id" })
            });
            const data = await res.json();
            if (data.status === "success") {
                document.getElementById('stats-display').innerText = 
                    `Telemetry Data Points: ${data.summary.segments}`;
            } else {
                document.getElementById('stats-display').innerText = "Access Denied: " + data.error;
            }
        } catch(e) {
            document.getElementById('stats-display').innerText = "Error loading diagnostics.";
        }
    }
    window.onload = loadStats;
</script>
{% endblock %}

